SELECT job_no AS jobNo , j.title , p.project_name AS projectName , p.project_code , j.job_status_no , j.job_type_no , j.priority , FN_GET_JOB_STATUS(j.job_status_no) AS job_status , FN_GET_JOB_TYPE(j.job_type_no) AS job_type , FN_GET_CODE_NAME(j.priority) AS priority_name , j.manager_id , j.files_no FROM job j JOIN project p ON j.project_no = p.project_no WHERE p.project_code = #{projectCode}
SELECT job_status_no , job_status FROM job_status ORDER BY job_status_no
SELECT job_type_no , job_type FROM job_type ORDER BY job_type_no
SELECT common_no , common_name FROM common WHERE parent_common_no = ( SELECT common_no FROM common WHERE common_name = '우선순위 코드' ) ORDER BY common_no
SELECT m.user_id , m.username FROM vw_member m JOIN vw_project p ON m.project_no = p.project_no JOIN users u ON m.user_id = u.user_id WHERE p.project_code = #{projectCode} ORDER BY u.username
SELECT j.job_no , j.title , p.project_name AS projectName FROM job j JOIN project p ON j.project_no = p.project_no WHERE project_code = #{projectCode}
SELECT JOB_SEQ.NEXTVAL FROM DUAL
INSERT INTO job ( job_no, title, content, priority, manager_id, user_id, public_role, start_date, end_date, add_date, progress, job_type_no, job_status_no, project_no, parent_job_no, files_no ) VALUES ( #{jobNo}, #{title}, #{content}, #{priority}, #{managerId}, #{userId}, #{publicRole}, #{startDate}, #{endDate}, CURRENT_TIMESTAMP, #{progress}, #{jobTypeNo}, #{jobStatusNo}, #{projectNo}, #{parentJobNo}, #{filesNo} )
UPDATE JOB SET PUBLIC_ROLE = #{publicRole}, TITLE = #{title}, CONTENT = #{content}, PRIORITY = #{priority}, START_DATE = #{startDate}, END_DATE = #{endDate}, PROGRESS = #{progress}, JOB_TYPE_NO = #{jobTypeNo}, JOB_STATUS_NO = #{jobStatusNo}, PARENT_JOB_NO = #{parentJobNo, jdbcType=INTEGER}, FILES_NO = #{filesNo, jdbcType=INTEGER} WHERE JOB_NO = #{jobNo}
INSERT INTO HISTORY ( history_no , comment , user_id , history_date , delete_date , job_no ) VALUES ( HISTORY_SEQ.NEXTVAL , #{comment} , #{userId} , CURRENT_TIMESTAMP , #{deleteDate} , #{jobNo} )
(SELECT project_no FROM project WHERE project_code = #{projectCode}), #{parentJobNo}, #{filesNo} )
SELECT j.job_no , j.manager_id , j.public_role , j.project_no , j.title , j.content , j.priority , FN_GET_CODE_NAME(j.priority) AS priority_name , j.start_date , end_date , j.progress , j.parent_job_no , j.files_no , j.user_id , j.job_type_no , j.job_status_no , jt.job_type , js.job_status FROM job j JOIN job_type jt ON j.job_type_no = jt.job_type_no JOIN job_status js ON j.job_status_no = js.job_status_no WHERE job_no = #{jobNo}
